def main():
    input = sys.stdin.read().split()
    ptr = 0
    N = int(input[ptr])
    ptr += 1
    D = list(map(int, input[ptr:ptr+N]))
    ptr += N
    L1 = int(input[ptr])
    C1 = int(input[ptr+1])
    K1 = int(input[ptr+2])
    ptr += 3
    L2 = int(input[ptr])
    C2 = int(input[ptr+1])
    K2 = int(input[ptr+2])
    ptr += 3

    # Precompute options for each D_i
    options = []
    for d in D:
        curr_options = []
        for x in range(0, K1 + 1):
            required = d - x * L1
            if required <= 0:
                y = 0
            else:
                y = (required + L2 - 1) // L2
            if y > K2:
                continue
            curr_options.append((x, y))
        if not curr_options:
            print(-1)
            return
        options.append(curr_options)

    # Initialize DP
    INF = float('inf')
    dp = [[INF] * (K2 + 1) for _ in range(K1 + 1)]
    dp[0][0] = 0

    for i in range(N):
        new_dp = [[INF] * (K2 + 1) for _ in range(K1 + 1)]
        for a_prev in range(K1 + 1):
            for b_prev in range(K2 + 1):
                if dp[a_prev][b_prev] == INF:
                    continue
                for x, y in options[i]:
                    new_a = a_prev + x
                    new_b = b_prev + y
                    if new_a <= K1 and new_b <= K2:
                        new_cost = dp[a_prev][b_prev] + x * C1 + y * C2
                        if new_cost < new_dp[new_a][new_b]:
                            new_dp[new_a][new_b] = new_cost
        dp = new_dp

    # Find the minimum value in dp
    res = INF
    for a in range(K1 + 1):
        for b in range(K2 + 1):
            if dp[a][b] < res:
                res = dp[a][b]
    if res == INF:
        print(-1)
    else:
        print(res)

