import sys

def main():
    input = sys.stdin.read().split()
    ptr = 0
    N = int(input[ptr])
    ptr += 1
    Q = int(input[ptr])
    ptr += 1
    A = list(map(int, input[ptr:ptr+N]))
    ptr += N

    INF = N + 1
    freq = [0] * (N + 1)
    for a in A:
        if 0 <= a <= N:
            freq[a] += 1

    # Prepare data for the segment tree
    data = [0] * (N + 1)
    for x in range(N + 1):
        if freq[x] == 0:
            data[x] = x
        else:
            data[x] = INF

    class SegmentTree:
        def __init__(self, data):
            self.n = len(data)
            self.size = 1
            while self.size < self.n:
                self.size <<= 1
            self.tree = [INF] * (2 * self.size)
            # Fill leaves
            for i in range(self.n):
                self.tree[self.size + i] = data[i]
            # Fill the rest of the leaves with INF
            for i in range(self.n, self.size):
                self.tree[self.size + i] = INF
            # Build the tree
            for i in range(self.size - 1, 0, -1):
                self.tree[i] = min(self.tree[2 * i], self.tree[2 * i + 1])

        def update(self, pos, value):
            pos += self.size
            self.tree[pos] = value
            while pos > 1:
                pos >>= 1
                new_val = min(self.tree[2 * pos], self.tree[2 * pos + 1])
                if self.tree[pos] == new_val:
                    break
                self.tree[pos] = new_val

        def get_min(self):
            return self.tree[1]

    st = SegmentTree(data)

    for _ in range(Q):
        i = int(input[ptr]) - 1  # Convert to 0-based index
        ptr += 1
        x = int(input[ptr])
        ptr += 1

        old_val = A[i]

        # Process old_val
        if 0 <= old_val <= N:
            if freq[old_val] == 1:
                freq[old_val] -= 1
                st.update(old_val, old_val)
            else:
                freq[old_val] -= 1

        # Update the array
        A[i] = x

        # Process new_val
        if 0 <= x <= N:
            if freq[x] == 0:
                freq[x] += 1
                st.update(x, INF)
            else:
                freq[x] += 1

        # Get mex
        mex = st.get_min()
        print(mex)

